  PushButton:   0x84000001,
  Glyph:        0x84000002,
  Array:        0x84000003,
  TextPen:      0x84000005,
  FillPen:      0x84000006,
  FillTextPen:  0x84000007,
  BgPen:        0x84000008,
  Current:      0x84000009,
  BevelStyle:   0x8400000D,
  Transparent:  0x8400000F,
  Justification:0x84000010,
  SoftStyle:    0x84000011,
